#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <base64.h>

typedef struct {
    char name[50];
    int age;
} Person;

void process_person(char *data) {
    Person *person = (Person *)malloc(sizeof(Person));
    memcpy(person, data, sizeof(Person));
    printf("Name: %s, Age: %d\n", person->name, person->age);
    free(person);
}

